import{_ as a,c as e,o as t,a4 as r}from"./chunks/framework.CzjLcc5X.js";const f=JSON.parse('{"title":"日本 -> 注意事項 -> 日本入境及隔離規定","description":"","frontmatter":{},"headers":[],"relativePath":"日本/注意事項/入境相關規定.md","filePath":"日本/_注意事項/入境相關規定.md","lastUpdated":1678802894000}'),i={name:"日本/注意事項/入境相關規定.md"},o=r('<h1 id="日本入境及隔離規定" tabindex="-1">日本入境及隔離規定 <a class="header-anchor" href="#日本入境及隔離規定" aria-label="Permalink to &quot;日本入境及隔離規定&quot;">​</a></h1><ul><li>入境日本時不執行入境檢疫，也無須進行居家隔離。</li><li>從日本回國，隔離限制已調整為「0+7」免居家隔離，僅需進行 7 天的自主防疫。</li></ul><h2 id="入境日本疫苗或是-pcr-証明" tabindex="-1">入境日本疫苗或是 PCR 証明 <a class="header-anchor" href="#入境日本疫苗或是-pcr-証明" aria-label="Permalink to &quot;入境日本疫苗或是 PCR 証明&quot;">​</a></h2><p>已「打滿」日本認可的 3 劑疫苗，並持有疫苗接種證明，入境時免提交 PCR 陰性證明。 若未打滿 3 劑或無接種日本認定之疫苗，須提交 72 小時內 PCR 陰性證明。</p><h3 id="日本認可的疫苗種類" tabindex="-1">日本認可的疫苗種類 <a class="header-anchor" href="#日本認可的疫苗種類" aria-label="Permalink to &quot;日本認可的疫苗種類&quot;">​</a></h3><ol><li>輝瑞 BNT</li><li>AZ</li><li>莫德納</li><li>嬌生（1 劑視為兩劑）</li><li>Novavax</li><li>Covaxin（印度的滅活疫苗）</li></ol><h3 id="疫苗接種證明申請" tabindex="-1">疫苗接種證明申請 <a class="header-anchor" href="#疫苗接種證明申請" aria-label="Permalink to &quot;疫苗接種證明申請&quot;">​</a></h3><p>可至衛福部申請，需準備健保卡卡號、戶口名簿戶號（或護照號碼）。 申請成功後，可獲得「數位新冠病毒健康證明」及 QRcode。 高端疫苗入境日本前須提交 PCR 陰性證明。</p><p><a href="https://dvc.mohw.gov.tw/vapa/apply/Index.init.ctr?openExternalBrowser=1" target="_blank" rel="noreferrer">衛福部申請連結</a></p><h2 id="入境日本前填寫-visit-japan-web" tabindex="-1">入境日本前填寫 Visit Japan Web <a class="header-anchor" href="#入境日本前填寫-visit-japan-web" aria-label="Permalink to &quot;入境日本前填寫 Visit Japan Web&quot;">​</a></h2><p>到日本旅遊時必須使用 Visit Japan Web 填寫並申報資料。 包含入國審查、海關申報及檢疫，使用 QRcode 可加速入境時間。</p><p><a href="https://www.vjw.digital.go.jp/main/#/vjwplo001" target="_blank" rel="noreferrer">Visit Japan Web</a></p><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><p><a href="https://www.boca.gov.tw/sp-foof-countrycp-01-29-77969-1.html" target="_blank" rel="noreferrer">外交部領事事務局 簽證及入境須知</a></p>',14),l=[o];function n(s,h,p,c,d,_){return t(),e("div",null,l)}const u=a(i,[["render",n]]);export{f as __pageData,u as default};
